package com.uktc.schoolInventory.controllers;

import com.uktc.schoolInventory.dto.UserLoginDto;
import com.uktc.schoolInventory.dto.response.LoginResponse;
import com.uktc.schoolInventory.models.User;
import com.uktc.schoolInventory.services.AuthService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import org.springframework.http.ResponseEntity;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;

@RestController
@RequestMapping("/api/auth")
public class AuthController {
    private final AuthService authService;

    public AuthController(AuthService authService) {
        this.authService = authService;
    }

    @PostMapping("/login")
    public ResponseEntity<LoginResponse> login(@RequestBody UserLoginDto userLoginDto, HttpSession session, HttpServletRequest request){
        User authendicatedUser = authService.authenticate(userLoginDto);

        session.setAttribute("userId",authendicatedUser.getId());
        session.setAttribute("userEmail",authendicatedUser.getEmail());
        session.setAttribute("userIsAdmin",authendicatedUser.getIsAdmin());

        // Set Spring Security authentication in context and session
        UsernamePasswordAuthenticationToken authToken =
            new UsernamePasswordAuthenticationToken(
                authendicatedUser.getEmail(),
                authendicatedUser.getPasswordHash(), // Use password hash for principal
                List.of(new SimpleGrantedAuthority(authendicatedUser.getIsAdmin() ? "ROLE_ADMIN" : "ROLE_USER"))
            );
        authToken.setDetails(authendicatedUser); // Attach the full user object as details
        SecurityContextHolder.getContext().setAuthentication(authToken);
        session.setAttribute("SPRING_SECURITY_CONTEXT", SecurityContextHolder.getContext());

        LoginResponse loginResponse = new LoginResponse(
                authendicatedUser.getId(),
                authendicatedUser.getEmail(),
                authendicatedUser.getIsAdmin()
        );
        return ResponseEntity.ok(loginResponse);
    }
}

package com.uktc.schoolInventory.controllers;

import com.uktc.schoolInventory.dto.UserLoginDto;
import com.uktc.schoolInventory.dto.UserRegisterDto;
import com.uktc.schoolInventory.dto.response.LoginResponse;
import com.uktc.schoolInventory.models.User;
import com.uktc.schoolInventory.services.AuthService;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpSession;
import jakarta.validation.Valid;
import org.springframework.http.ResponseEntity;
import org.springframework.security.authentication.UsernamePasswordAuthenticationToken;
import org.springframework.security.core.authority.SimpleGrantedAuthority;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestBody;
import org.springframework.web.bind.annotation.RequestMapping;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;

@RestController
@RequestMapping("/api/auth")
public class AuthController {
    private final AuthService authService;

    public AuthController(AuthService authService) {
        this.authService = authService;
    }

    @PostMapping("/login")
    public ResponseEntity<LoginResponse> login(@Valid @RequestBody UserLoginDto userLoginDto, HttpSession session, HttpServletRequest request){
        User authendicatedUser = authService.authenticate(userLoginDto);

        session.setAttribute("userId",authendicatedUser.getId());
        session.setAttribute("userEmail",authendicatedUser.getEmail());
        session.setAttribute("userIsAdmin",authendicatedUser.getIsAdmin());

        // Set Spring Security authentication in context and session
        UsernamePasswordAuthenticationToken authToken =
            new UsernamePasswordAuthenticationToken(
                authendicatedUser.getEmail(),
                authendicatedUser.getPasswordHash(), // Use password hash for principal
                List.of(new SimpleGrantedAuthority(authendicatedUser.getIsAdmin() ? "ROLE_ADMIN" : "ROLE_USER"))
            );
        authToken.setDetails(authendicatedUser); // Attach the full user object as details
        SecurityContextHolder.getContext().setAuthentication(authToken);
        session.setAttribute("SPRING_SECURITY_CONTEXT", SecurityContextHolder.getContext());

        LoginResponse loginResponse = new LoginResponse(
                authendicatedUser.getId(),
                authendicatedUser.getEmail(),
                authendicatedUser.getIsAdmin()
        );
        return ResponseEntity.ok(loginResponse);
    }

    @PostMapping("/register")
    public ResponseEntity<?> register(@Valid @RequestBody UserRegisterDto userRegisterDto) {
        authService.register(userRegisterDto);
        return ResponseEntity.ok().build();
    }
}

package com.uktc.schoolInventory.controllers;

import com.uktc.schoolInventory.exception.ResourceNotFoundException;
import com.uktc.schoolInventory.exception.UnauthorizedActionException;
import com.uktc.schoolInventory.models.User;
import com.uktc.schoolInventory.repositories.UserRepository;
import org.springframework.web.bind.annotation.*;
import java.util.List;

@RestController
@RequestMapping("/api/users")
public class UserController {

    private final UserRepository userRepository;

    public UserController(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    @GetMapping
    public List<User> getAllUsers() {
        return userRepository.findAll();
    }

    @PostMapping
    public User createUser(@RequestBody User user) {
        return userRepository.save(user);
    }

    // Approve registration
    @PutMapping("/{id}/approve")
    public String approveUser(@PathVariable Long id, @RequestParam Long requesterId) {
        if (!requesterId.equals(1L)) {
            throw new UnauthorizedActionException("Only the Superuser can approve registrations");
        }
        User user = userRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("User not found with id: " + id));
        return "User " + user.getFirstName() + " approved successfully.";
    }

    // Grant admin rights
    @PutMapping("/{id}/make-admin")
    public String makeAdmin(@PathVariable Long id, @RequestParam Long requesterId) {
        if (!requesterId.equals(1L)) {
            throw new UnauthorizedActionException("Only the Superuser can grant admin rights");
        }
        User user = userRepository.findById(id)
                .orElseThrow(() -> new ResourceNotFoundException("User not found with id: " + id));
        user.setIsAdmin(true);
        userRepository.save(user);
        return "User " + user.getFirstName() + " is now an administrator.";
    }

    // Delete user
    @DeleteMapping("/{id}")
    public String deleteUser(@PathVariable Long id, @RequestParam Long requesterId) {
        if (!requesterId.equals(1L)) {
            throw new UnauthorizedActionException("Only the Superuser can delete users");
        }
        if (!userRepository.existsById(id)) {
            throw new ResourceNotFoundException("User not found with id: " + id);
        }
        userRepository.deleteById(id);
        return "User with ID " + id + " deleted successfully.";
    }
}

