package com.uktc.schoolInventory.models;

import java.time.OffsetDateTime;

import com.fasterxml.jackson.annotation.JsonIgnoreProperties;
import com.uktc.schoolInventory.config.EquipmentConditionConverter;
import com.uktc.schoolInventory.config.EquipmentStatusConverter;

import jakarta.persistence.Column;
import jakarta.persistence.Convert;
import jakarta.persistence.Entity;
import jakarta.persistence.FetchType;
import jakarta.persistence.GeneratedValue;
import jakarta.persistence.GenerationType;
import jakarta.persistence.Id;
import jakarta.persistence.JoinColumn;
import jakarta.persistence.ManyToOne;
import jakarta.persistence.Table;
import lombok.Data;

@Entity
@Table(name = "equipment")
@Data
public class Equipment {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(nullable = false)
    private String name;

    // Връзка към таблица equipment_types
    @Column(name = "type_id")
    private Integer typeId;

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "type_id", insertable = false, updatable = false)
    @JsonIgnoreProperties({"hibernateLazyInitializer", "handler"})
    private EquipmentType type;

    @Column(name = "serial_number", unique = true, nullable = false)
    private String serialNumber;

    @Convert(converter = EquipmentStatusConverter.class)
    @Column(name = "status")
    private EquipmentStatus status = EquipmentStatus.Available;

    @Convert(converter = EquipmentConditionConverter.class)
    @Column(name = "current_condition")
    private EquipmentCondition currentCondition;

    // Връзка към таблица locations
    @Column(name = "location_id")
    private Integer locationId;

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "location_id", insertable = false, updatable = false)
    @JsonIgnoreProperties({"hibernateLazyInitializer", "handler"})
    private Location location;

    @Column(name = "photo_url", length = 1000)
    private String photoUrl;

    @Column(name = "is_assigned")
    private boolean isAssigned = false;

    @Column(name = "assigned_to")
    private String assignedTo;

    @Column(name = "created_at", insertable = false, updatable = false)
    private OffsetDateTime createdAt;

    @Column(name = "updated_at", insertable = false, updatable = false)
    private OffsetDateTime updatedAt;
}

package com.uktc.schoolInventory.models;

import java.time.OffsetDateTime;

import com.fasterxml.jackson.annotation.JsonIgnoreProperties;
import com.uktc.schoolInventory.config.EquipmentConditionConverter;
import com.uktc.schoolInventory.config.EquipmentStatusConverter;

import jakarta.persistence.Column;
import jakarta.persistence.Convert;
import jakarta.persistence.Entity;
import jakarta.persistence.FetchType;
import jakarta.persistence.GeneratedValue;
import jakarta.persistence.GenerationType;
import jakarta.persistence.Id;
import jakarta.persistence.JoinColumn;
import jakarta.persistence.ManyToOne;
import jakarta.persistence.Table;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.Pattern;
import jakarta.validation.constraints.Size;
import lombok.Data;

@Entity
@Table(name = "equipment")
@Data
public class Equipment {

    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(nullable = false)
    @NotBlank(message = "Name is required")
    @Size(max = 255, message = "Name must be at most 255 characters")
    @Pattern(regexp = "^[^<>&\"']*$", message = "Name contains invalid characters")
    private String name;

    // Връзка към таблица equipment_types
    @Column(name = "type_id")
    private Integer typeId;

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "type_id", insertable = false, updatable = false)
    @JsonIgnoreProperties({"hibernateLazyInitializer", "handler"})
    private EquipmentType type;

    @Column(name = "serial_number", unique = true, nullable = false)
    @NotBlank(message = "Serial number is required")
    @Size(max = 100, message = "Serial number must be at most 100 characters")
    @Pattern(regexp = "^[^<>&\"']*$", message = "Serial number contains invalid characters")
    private String serialNumber;

    @Convert(converter = EquipmentStatusConverter.class)
    @Column(name = "status")
    private EquipmentStatus status = EquipmentStatus.Available;

    @Convert(converter = EquipmentConditionConverter.class)
    @Column(name = "current_condition")
    private EquipmentCondition currentCondition;

    // Връзка към таблица locations
    @Column(name = "location_id")
    private Integer locationId;

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "location_id", insertable = false, updatable = false)
    @JsonIgnoreProperties({"hibernateLazyInitializer", "handler"})
    private Location location;

    @Column(name = "photo_url", length = 1000)
    @Pattern(regexp = "^[^<>&\"']*$", message = "Photo URL contains invalid characters")
    private String photoUrl;

    @Column(name = "is_assigned")
    private boolean isAssigned = false;

    @Column(name = "assigned_to")
    @Pattern(regexp = "^[^<>&\"']*$", message = "Assigned to contains invalid characters")
    private String assignedTo;

    @Column(name = "created_at", insertable = false, updatable = false)
    private OffsetDateTime createdAt;

    @Column(name = "updated_at", insertable = false, updatable = false)
    private OffsetDateTime updatedAt;
}

package com.uktc.schoolInventory.models;

import jakarta.persistence.*;
import lombok.Data;
import java.time.OffsetDateTime;

@Entity
@Table(name = "users") // Свързва се с таблицата users в SQL [cite: 58]
@Data // Lombok автоматично прави getter/setter
public class User {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(name = "first_name")
    private String firstName;

    @Column(name = "last_name")
    private String lastName;

    @Column(unique = true, nullable = false)
    private String email;

    @Column(name = "password_hash", nullable = false)
    private String passwordHash;

    @Column(name = "isadmin")
    private Boolean isAdmin = false;

    @Column(name = "approved")
    private Boolean approved = false;

    @Column(name = "created_at")
    private OffsetDateTime createdAt = OffsetDateTime.now();
}

package com.uktc.schoolInventory.models;

import jakarta.persistence.*;
import jakarta.validation.constraints.Email;
import jakarta.validation.constraints.NotBlank;
import jakarta.validation.constraints.Pattern;
import jakarta.validation.constraints.Size;
import lombok.Data;
import java.time.OffsetDateTime;

@Entity
@Table(name = "users") // Свързва се с таблицата users в SQL [cite: 58]
@Data // Lombok автоматично прави getter/setter
public class User {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(name = "first_name")
    @NotBlank(message = "First name is required")
    @Size(max = 50, message = "First name must be at most 50 characters")
    @Pattern(regexp = "^[^<>&\"']*$", message = "First name contains invalid characters")
    private String firstName;

    @Column(name = "last_name")
    @NotBlank(message = "Last name is required")
    @Size(max = 50, message = "Last name must be at most 50 characters")
    @Pattern(regexp = "^[^<>&\"']*$", message = "Last name contains invalid characters")
    private String lastName;

    @Column(unique = true, nullable = false)
    @NotBlank(message = "Email is required")
    @Email(message = "Invalid email format")
    @Pattern(regexp = "^[^<>&\"']*$", message = "Email contains invalid characters")
    private String email;

    @Column(name = "password_hash", nullable = false)
    @NotBlank(message = "Password hash is required")
    @Pattern(regexp = "^[^<>&\"']*$", message = "Password hash contains invalid characters")
    private String passwordHash;

    @Column(name = "isadmin")
    private Boolean isAdmin = false;

    @Column(name = "approved")
    private Boolean approved = false;

    @Column(name = "created_at")
    private OffsetDateTime createdAt = OffsetDateTime.now();
}
